def classify(code):
    if 200 <= code < 300:
        return "ok"
    elif 300 <= code < 400:
        return "redirect"
    elif 400 <= code < 500:
        return "client error"
    elif 500 <= code < 600:
        return "server error"
    else:
        return "weird"

print(classify(404))
